// Parse the JSON data from the file
const fileContent = $input.first().binary.data;
const text = Buffer.from(fileContent.data, 'base64').toString('utf8');
const posts = JSON.parse(text);

// Filter only unposted items
const unposted = posts.filter(p => !p.posted);

if (unposted.length === 0) {
  throw new Error('No more posts to publish! Add more posts to your dataset.');
}

// Take the first unposted item
const nextPost = unposted[0];

return [{
  json: {
    id: nextPost.id,
    text: nextPost.text,
    imageUrl: nextPost.imageUrl || '',
    hasImage: !!(nextPost.imageUrl && nextPost.imageUrl.trim() !== '' && !nextPost.imageUrl.includes('example.com')),
    allPosts: posts,
    totalPosts: posts.length,
    remainingPosts: unposted.length
  }
}];

// Mark the post as 'posted' in the dataset
const fs = require('fs');
const filePath = '/data/posts.json';

// Read current data
const fileContent = fs.readFileSync(filePath, 'utf8');
const posts = JSON.parse(fileContent);

// Find and mark the posted item
const postedId = $('🔄 Get Next Unposted').first().json.id;
const postIndex = posts.findIndex(p => p.id === postedId);

if (postIndex !== -1) {
  posts[postIndex].posted = true;
}

// Write back
fs.writeFileSync(filePath, JSON.stringify(posts, null, 2), 'utf8');

return [{
  json: {
    success: true,
    postedId: postedId,
    remainingPosts: posts.filter(p => !p.posted).length,
    message: `Post #${postedId} published! ${posts.filter(p => !p.posted).length} posts remaining.`
  }
}];
